mapper.sql:
j.deleted_at IS NULL

  AND j.created_by = #{ownerOnlyUserId}


  AND j.status::text IN
  #{s}


  AND (
    j.title ILIKE '%' || #{q.keyword} || '%'
    OR to_tsvector('english', coalesce(j.description, ''))
       @@ plainto_tsquery('english', #{q.keyword})
  )


  AND j.status::text IN
  #{s}


  AND j.work_type::text IN
  #{w}


  AND j.level::text IN
  #{l}


  AND j.department_id = #{q.departmentId}


  AND EXISTS (
    SELECT 1 FROM job_tags jt
    JOIN tags t ON t.id = jt.tag_id
    WHERE jt.job_id = j.id
      AND t.slug IN
      #{s}
  )
